import numpy as np

def queue_latency(arrival_rate_rps: float,
                  service_rate_rps: float,
                  prefill_ms: float) -> dict:
    """M/M/1 queue model for LLM TTFT estimation."""
    rho = arrival_rate_rps / service_rate_rps   # utilisation
    if rho >= 1.0:
        return {"queue_wait_ms": float("inf"), "ttft_ms": float("inf")}
    # mean queue wait in M/M/1
    queue_wait_s = rho / (service_rate_rps * (1 - rho))
    ttft = prefill_ms + queue_wait_s * 1000
    return {
        "utilisation": round(rho, 3),
        "queue_wait_ms": round(queue_wait_s * 1000, 1),
        "ttft_ms": round(ttft, 1),
    }

# 70B model: 1 req/s service rate, 200ms prefill
for load in [0.3, 0.6, 0.8, 0.9, 0.95]:
    print(f"load={load:.2f}: {queue_latency(load, 1.0, 200)}")

# load=0.30: {'utilisation': 0.3, 'queue_wait_ms': 85.7, 'ttft_ms': 285.7}
