// k6 load test — ramp up from 1 to 20 concurrent users
import http from "k6/http";
import { check, sleep } from "k6";

export const options = {
  stages: [
    { duration: "1m", target: 5 },
    { duration: "3m", target: 20 },
    { duration: "1m", target: 0 },
  ],
  thresholds: {
    http_req_duration: ["p(95)<15000"],  // 15s E2E p95 SLO
    // Note: k6 measures E2E only; no TTFT support for streaming
  },
};

const PROMPT = "Explain transformer attention in three sentences.";

export default function () {
  const payload = JSON.stringify({
    model: "meta-llama/Llama-3-70b-instruct",
    messages: [{ role: "user", content: PROMPT }],
    max_tokens: 200,
    stream: false,   // k6 does not stream; use vllm benchmark for TTFT
  });

  const r = http.post("http://vllm-gateway/v1/chat/completions", payload, {
    headers: { "Content-Type": "application/json" },
    timeout: "30s",
  });

  check(r, { "status 200": (res) => res.status === 200 });
}
